arguments.new_str:
email_counts = {}
for user in users:
    try:
        # Handle duplicate emails by appending counter
        original_email = user['email']
        if original_email in email_counts:
            email_counts[original_email] += 1
            user['email'] = f"{original_email.split('@')[0]}+{email_counts[original_email]}@{original_email.split('@')[1]}"
        else:
            email_counts[original_email] = 0

        new_db.insert('users_v2', user)
        migrated += 1
    except Exception as e:
        print(f'Failed to migrate user {user["id"]}: {e}', file=sys.stderr)
        failed += 1
